import React, { useState } from "react";

export default function CreateGoalScreen({ onBack, onCreate }) {
  const [title, setTitle] = useState("");
  const [target, setTarget] = useState("");
  const [icon, setIcon] = useState("🎯"); // default icon
  const [color, setColor] = useState("#00875A"); // default color

  const handleCreate = () => {
    if (!title || !target) return;

    const newGoal = {
      id: Date.now(),
      title,
      target: Number(target),
      current: 0,
      icon,
      color: `bg-${color.replace("#", "")}-500`, // Tailwind-friendly
    };

    onCreate(newGoal); // add to goals list in App.jsx
    onBack(); // go back to Goals tab
  };

  return (
    <div className="p-6 min-h-screen flex flex-col">
      <button onClick={onBack} className="mb-6 text-gray-500">
        ← Back
      </button>

      <h2 className="text-2xl font-bold mb-4">Create a New Goal</h2>

      <input
        type="text"
        placeholder="Goal Title"
        value={title}
        onChange={(e) => setTitle(e.target.value)}
        className="mb-4 p-3 rounded-xl border border-gray-300"
      />

      <input
        type="number"
        placeholder="Target Amount"
        value={target}
        onChange={(e) => setTarget(e.target.value)}
        className="mb-4 p-3 rounded-xl border border-gray-300"
      />

      <input
        type="text"
        placeholder="Icon (Emoji)"
        value={icon}
        onChange={(e) => setIcon(e.target.value)}
        className="mb-4 p-3 rounded-xl border border-gray-300"
      />

      <input
        type="color"
        value={color}
        onChange={(e) => setColor(e.target.value)}
        className="mb-4 w-20 h-10 p-1 rounded-xl"
      />

      <button
        onClick={handleCreate}
        className="mt-auto py-3 bg-emerald-500 text-white rounded-xl font-bold"
      >
        Create Goal
      </button>
    </div>
  );
}
